// Get data directly from trigger - no need for extra API call
const triggerData = $input.first().json;

// Extract contact_id from multiple possible locations
const contactId = triggerData.contact_id || triggerData.id || '';

if (!contactId) {
  throw new Error('Missing contact_id in trigger data: ' + JSON.stringify(triggerData));
}

// Extract lead data - handle both direct lead_data and flat structure
let lead = {};

if (triggerData.lead_data) {
  // Data passed via lead_data object
  lead = {
    name: triggerData.lead_data.name || triggerData.contact_name || '',
    phone: triggerData.lead_data.phone || '',
    email: triggerData.lead_data.email || '',
    source: triggerData.lead_data.source || 'Unknown',
    message: triggerData.lead_data.message || '',
    interactions: triggerData.lead_data.interaction_count || 1
  };
} else {
  // Flat structure fallback
  lead = {
    name: triggerData.name || triggerData.contact_name || '',
    phone: triggerData.phone || '',
    email: triggerData.email || '',
    source: triggerData.source || 'Unknown',
    message: triggerData.message || '',
    interactions: triggerData.interaction_count || 1
  };
}

let score = 0;
let reasons = [];

// Phone scoring (clean phone number)
const cleanPhone = (lead.phone || '').toString().replace(/\D/g, '');
if (cleanPhone.length >= 10) {
  score += 2;
  reasons.push('has phone');
}

// Email scoring
if (lead.email && lead.email.includes('@')) {
  score += 1;
  reasons.push('has email');
}

// Message intent scoring
const msg = (lead.message || '').toLowerCase();
const buyingKeywords = ['buy', 'price', 'cost', 'interested', 'want', 'need', 'purchase', 'quote'];
const serviceKeywords = ['website', 'build', 'develop', 'product', 'service', 'demo', 'appointment', 'meeting', 'call'];

if (buyingKeywords.some(k => msg.includes(k))) {
  score += 3;
  reasons.push('buying intent');
}

if (serviceKeywords.some(k => msg.includes(k))) {
  score += 2;
  reasons.push('specific inquiry');
}

// Engagement scoring
if (lead.interactions > 1) {
  score += 1;
  reasons.push('returning');
}

if ((lead.message || '').length > 50) {
  score += 1;
  reasons.push('detailed');
}

// Normalize score between 1-10
score = Math.min(10, Math.max(1, score));

// Determine tier and action
const tier = score >= 8 ? 'Hot' : score >= 5 ? 'Warm' : 'Cold';
const action = tier === 'Hot' ? 'Call immediately' : tier === 'Warm' ? 'Send follow-up within 24h' : 'Add to nurture sequence';

return {
  json: {
    contact_id: contactId,
    score: score,
    tier: tier,
    reason: reasons.join(', ') || 'New lead',
    suggested_action: action,
    lead_data: lead
  }
};

const data = $('Score Lead').item.json;
return {
  json: {
    alert_type: 'hot_lead',
    contact_data: {
      contact_id: data.contact_id,
      name: data.lead_data.name,
      phone: data.lead_data.phone,
      email: data.lead_data.email,
      interest: data.lead_data.message,
      score: data.score,
      suggested_action: data.suggested_action
    }
  }
};

const data = $('Score Lead').item.json;
return {
  json: {
    contact_id: data.contact_id,
    tier: data.tier.toLowerCase(),
    name: data.lead_data.name,
    phone: data.lead_data.phone,
    email: data.lead_data.email,
    interest: data.lead_data.message,
    score: data.score,
    suggested_action: data.suggested_action
  }
};
